using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Tool Definitions ---

var notes = new List<string>();

[Description("Search the web for information on a query. Returns a list of relevant snippets.")]
string WebSearch([Description("The search query")] string query)
{
    // Simulated web search results for demonstration purposes.
    // In production, replace with a real search API (e.g., Bing Search).
    Console.WriteLine($"  [Tool] Searching the web for: \"{query}\"");
    var results = query.ToLowerInvariant() switch
    {
        var q when q.Contains("quantum computing") => """
            1. Quantum computers use qubits that can exist in superposition, enabling parallel computation.
            2. Google achieved quantum supremacy in 2019 with their Sycamore processor solving a problem in 200 seconds that would take classical supercomputers 10,000 years.
            3. IBM launched a 1,121-qubit processor called Condor in 2023, pushing toward practical quantum advantage.
            4. Key applications include cryptography, drug discovery, materials science, and optimization problems.
            5. Major challenges remain: qubit decoherence, error correction overhead, and extreme cooling requirements (near absolute zero).
            """,
        var q when q.Contains("artificial intelligence") || q.Contains(" ai ") => """
            1. Large language models (LLMs) like GPT-4 and Claude demonstrate emergent reasoning capabilities.
            2. AI agents that use tool-calling to interact with external systems are a rapidly growing paradigm.
            3. Multimodal AI systems can process text, images, audio, and video simultaneously.
            4. Concerns include hallucination, bias, energy consumption, and alignment with human values.
            5. The global AI market is projected to exceed $1.8 trillion by 2030.
            """,
        _ => $"""
            1. "{query}" is an active area of research with growing academic and industry interest.
            2. Recent breakthroughs have expanded practical applications across multiple domains.
            3. Interdisciplinary collaboration is accelerating progress in this field.
            4. Funding for research in this area has increased significantly in recent years.
            5. Open-source contributions continue to democratize access to key tools and datasets.
            """
    };
    return results;
}

[Description("Save a research note for later reference. Use this to record important findings.")]
string SaveNote([Description("The note content to save")] string note)
{
    Console.WriteLine($"  [Tool] Saving note: \"{note[..Math.Min(note.Length, 60)]}...\"");
    notes.Add(note);
    return $"Note saved. You now have {notes.Count} note(s).";
}

[Description("Retrieve all saved research notes.")]
string GetNotes()
{
    Console.WriteLine("  [Tool] Retrieving all notes");
    if (notes.Count == 0)
        return "No notes saved yet.";
    return string.Join("\n---\n", notes.Select((n, i) => $"Note {i + 1}: {n}"));
}

// --- Agent Setup ---

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "sk-placeholder";
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

var openAiClient = new OpenAIClient(apiKey);
IChatClient chatClient = openAiClient.GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new[]
{
    AIFunctionFactory.Create(WebSearch),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetNotes),
};

var chatOptions = new ChatOptions { Tools = [.. tools] };

// --- Agent Loop ---

Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("  Research Agent - AI-Powered Topic Research");
Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine();

Console.Write("Enter a research topic (or press Enter for 'quantum computing'): ");
var topic = Console.ReadLine();
if (string.IsNullOrWhiteSpace(topic))
    topic = "quantum computing";

Console.WriteLine($"\nResearching: {topic}\n");

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the given topic using the available tools.
        Follow this process:
        1. Search the web for key information about the topic (perform 2-3 searches with different angles).
        2. Save important findings as notes using the SaveNote tool.
        3. After gathering enough information, retrieve your notes and produce a well-structured summary.
        Be thorough but concise. Always cite the source of your findings in notes.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary: {topic}")
};

Console.WriteLine("Agent is working...\n");

var response = await chatClient.GetResponseAsync(messages, chatOptions);

Console.WriteLine("\n═══════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n═══════════════════════════════════════════");
Console.WriteLine($"  Notes collected: {notes.Count}");
Console.WriteLine("═══════════════════════════════════════════");

